from typing import Dict, Union, Optional
from uuid import uuid4
import time

class SessionManager:
    def __init__(self):
        self.sessions: Dict[str, Dict[str, Union[float, float, bool]]] = {}

    def create_session(self, timeout: int) -> str:
        session_id: str = str(uuid4())
        current_time: float = time.time()
        self.sessions[session_id] = {
            "timeout": timeout,
            "created_at": current_time,
            "active": True
        }
        return session_id

    def close_session(self, session_id: str) -> bool:
        if session_id not in self.sessions:
            raise ValueError(f"Session {session_id} does not exist")

        self.sessions[session_id]["active"] = False
        return True

    def modify_session(self, session_id: str, new_timeout: int) -> bool:
        if session_id not in self.sessions:
            raise ValueError(f"Session {session_id} does not exist")

        self.sessions[session_id]["timeout"] = new_timeout
        return True

    def get_session_status(self, session_id: str) -> str:
        if session_id not in self.sessions:
            raise ValueError(f"Session {session_id} does not exist")

        return "active" if self.sessions[session_id]["active"] else "closed"
