public class SmartHomeSystem {
    // Constants
    private static final String[] VALID_ROOMS = {"living room", "bedroom", "kitchen", "bathroom", "office"};
    private static final int DEFAULT_BRIGHTNESS = 50;
    private static final int MIN_BRIGHTNESS = 0;
    private static final int MAX_BRIGHTNESS = 100;
    private static final String STATUS_ON = "On";
    private static final String STATUS_OFF = "Off";

    // Room status tracking
    private boolean[] roomLightStatus;
    private int[] roomBrightnessLevels;
    private String[] commandHistory;
    private int historyIndex;

    public SmartHomeSystem() {
        roomLightStatus = new boolean[VALID_ROOMS.length];
        roomBrightnessLevels = new int[VALID_ROOMS.length];
        commandHistory = new String[100]; // Store last 100 commands
        historyIndex = 0;

        // Initialize all rooms with lights off and default brightness
        for (int i = 0; i < VALID_ROOMS.length; i++) {
            roomLightStatus[i] = false;
            roomBrightnessLevels[i] = DEFAULT_BRIGHTNESS;
        }
    }

    private int getRoomIndex(String room) {
        for (int i = 0; i < VALID_ROOMS.length; i++) {
            if (VALID_ROOMS[i].equalsIgnoreCase(room)) {
                return i;
            }
        }
        return -1;
    }

    private void logCommand(String command) {
        commandHistory[historyIndex] = command;
        historyIndex = (historyIndex + 1) % commandHistory.length;
    }

    public void turnOn(String room) {
        int roomIndex = getRoomIndex(room);
        if (roomIndex == -1) {
            System.out.println("Error: Room '" + room + "' does not exist in the system.");
            return;
        }

        roomLightStatus[roomIndex] = true;
        logCommand("Turned on lights in " + room);
        System.out.println("Lights turned on in " + room);
    }

    public void turnOff(String room) {
        int roomIndex = getRoomIndex(room);
        if (roomIndex == -1) {
            System.out.println("Error: Room '" + room + "' does not exist in the system.");
            return;
        }

        roomLightStatus[roomIndex] = false;
        logCommand("Turned off lights in " + room);
        System.out.println("Lights turned off in " + room);
    }

    public void adjustBrightness(String room, int level) {
        int roomIndex = getRoomIndex(room);
        if (roomIndex == -1) {
            System.out.println("Error: Room '" + room + "' does not exist in the system.");
            return;
        }

        if (level < MIN_BRIGHTNESS || level > MAX_BRIGHTNESS) {
            System.out.println("Error: Brightness level must be between " + MIN_BRIGHTNESS + " and " + MAX_BRIGHTNESS);
            return;
        }

        roomBrightnessLevels[roomIndex] = level;
        logCommand("Adjusted brightness in " + room + " to " + level);
        System.out.println("Brightness in " + room + " adjusted to " + level);
    }

    public String checkStatus(String room) {
        int roomIndex = getRoomIndex(room);
        if (roomIndex == -1) {
            return "Error: Room '" + room + "' does not exist in the system.";
        }

        String status = roomLightStatus[roomIndex] ? STATUS_ON : STATUS_OFF;
        int brightness = roomBrightnessLevels[roomIndex];

        logCommand("Checked status of " + room);
        return "Room: " + room + ", Status: " + status + ", Brightness: " + brightness;
    }

    public static void main(String[] args) {
        SmartHomeSystem smartHome = new SmartHomeSystem();

        // Example usage
        smartHome.turnOn("living room");
        smartHome.adjustBrightness("living room", 75);
        System.out.println(smartHome.checkStatus("living room"));

        smartHome.turnOn("bedroom");
        smartHome.adjustBrightness("bedroom", 30);
        System.out.println(smartHome.checkStatus("bedroom"));

        smartHome.turnOff("living room");
        System.out.println(smartHome.checkStatus("living room"));

        // Test invalid input
        smartHome.turnOn("garage");
        smartHome.adjustBrightness("bedroom", 150);
    }
}
