class HardwareStore {
public:
    void addItem(const std::string& itemName, int quantity, double price);
    void removeItem(const std::string& itemName);
    void updateItem(const std::string& itemName, int newQuantity, double newPrice);
    void displayInventory() const;
    void processCommand(const std::string& command);

protected:
    void displayErrorMessage(const std::string& message) const;
    std::vector<std::string> parseCommand(const std::string& command) const;

private:
    struct InventoryItem {
        std::string name;
        int quantity = 0;
        double price = 0.0;
    };

    std::unordered_map<std::string, InventoryItem> inventory;
};

void HardwareStore::addItem(const std::string& itemName, int quantity, double price) {
    InventoryItem item;
    item.name = itemName;
    item.quantity = quantity;
    item.price = price;

    inventory[itemName] = item;
    std::cout << "Added: " << itemName << std::endl;
}

void HardwareStore::removeItem(const std::string& itemName) {
    if (inventory.find(itemName) != inventory.end()) {
        inventory.erase(itemName);
        std::cout << "Removed: " << itemName << std::endl;
    } else {
        displayErrorMessage("Item '" + itemName + "' not found in inventory");
    }
}

void HardwareStore::updateItem(const std::string& itemName, int newQuantity, double newPrice) {
    if (inventory.find(itemName) != inventory.end()) {
        inventory[itemName].quantity = newQuantity;
        inventory[itemName].price = newPrice;
        std::cout << "Updated: " << itemName << std::endl;
    } else {
        displayErrorMessage("Item '" + itemName + "' not found in inventory");
    }
}

void HardwareStore::displayInventory() const {
    if (inventory.empty()) {
        std::cout << "Inventory is empty" << std::endl;
        return;
    }

    std::cout << std::left << std::setw(20) << "Item" 
              << std::setw(10) << "Quantity" 
              << std::setw(10) << "Price" << std::endl;
    std::cout << std::string(40, '-') << std::endl;

    for (const auto& pair : inventory) {
        const InventoryItem& item = pair.second;
        std::cout << std::left << std::setw(20) << item.name 
                  << std::setw(10) << item.quantity 
                  << "$" << std::fixed << std::setprecision(2) << item.price << std::endl;
    }
}

void HardwareStore::displayErrorMessage(const std::string& message) const {
    std::cerr << "Error: " << message << std::endl;
}

std::vector<std::string> HardwareStore::parseCommand(const std::string& command) const {
    std::vector<std::string> tokens;
    std::string token;

    for (size_t i = 0; i < command.length(); i++) {
        if (command[i] == ' ') {
            if (!token.empty()) {
                tokens.push_back(token);
                token.clear();
            }
        } else {
            token += command[i];
        }
    }

    if (!token.empty()) {
        tokens.push_back(token);
    }

    return tokens;
}

void HardwareStore::processCommand(const std::string& command) {
    std::vector<std::string> tokens = parseCommand(command);

    if (tokens.empty()) {
        return;
    }

    std::string action = tokens[0];

    if (action == "ADD" && tokens.size() == 4) {
        try {
            int quantity = std::stoi(tokens[2]);
            double price = std::stod(tokens[3]);
            addItem(tokens[1], quantity, price);
        } catch (const std::exception& e) {
            displayErrorMessage("Invalid quantity or price format");
        }
    } else if (action == "REMOVE" && tokens.size() == 2) {
        removeItem(tokens[1]);
    } else if (action == "UPDATE" && tokens.size() == 4) {
        try {
            int newQuantity = std::stoi(tokens[2]);
            double newPrice = std::stod(tokens[3]);
            updateItem(tokens[1], newQuantity, newPrice);
        } catch (const std::exception& e) {
            displayErrorMessage("Invalid quantity or price format");
        }
    } else if (action == "DISPLAY" && tokens.size() == 1) {
        displayInventory();
    } else {
        displayErrorMessage("Invalid command format");
    }
}

int main() {
    HardwareStore store;
    std::string command;

    std::cout << "Hardware Store Inventory System" << std::endl;
    std::cout << "Available commands:" << std::endl;
    std::cout << "  ADD item_name quantity price" << std::endl;
    std::cout << "  REMOVE item_name" << std::endl;
    std::cout << "  UPDATE item_name new_quantity new_price" << std::endl;
    std::cout << "  DISPLAY" << std::endl;
    std::cout << "  EXIT" << std::endl;

    while (true) {
        std::cout << "\n> ";
        std::getline(std::cin, command);

        if (command == "EXIT") {
            break;
        }

        store.processCommand(command);
    }

    return 0;
}
