function processChartData(dataPoints) {
  let buckets = {};
  let hourlyAverages = {};

  for (let i = 0; i < dataPoints.length; i++) {
    let dataPoint = dataPoints[i];
    let timestamp = new Date(dataPoint.timestamp);
    let hour = timestamp.getHours();

    if (!buckets[hour]) {
      buckets[hour] = [];
    }

    buckets[hour].push(dataPoint.value);
  }

  for (let hour in buckets) {
    let values = buckets[hour];
    let sum = 0;

    for (let j = 0; j < values.length; j++) {
      sum += values[j];
    }

    let average = values.length > 0 ? sum / values.length : 0;
    hourlyAverages[hour] = average;
  }

  return hourlyAverages;
}
