}

impl Authentication {
    fn new() -> Self {
        Authentication {
            credentials: HashMap::new(),
        }
    }

    fn register_user(&mut self, username: String, password: String) {
        self.credentials.insert(username, password);
    }

    fn login_user(&self, username: String, password: String) -> String {
        match self.credentials.get(&username) {
            Some(stored_password) if stored_password == &password => "Success".to_string(),
            _ => "Failure".to_string(),
        }
    }

    fn update_password(&mut self, username: String, old_password: String, new_password: String) -> String {
        match self.credentials.get(&username) {
            Some(stored_password) if stored_password == &old_password => {
                self.credentials.insert(username, new_password);
                "Updated".to_string()
            },
            _ => "Invalid".to_string(),
        }
    }

    fn delete_user(&mut self, username: String) -> String {
        if self.credentials.remove(&username).is_some() {
            "Deleted".to_string()
        } else {
            "User not found".to_string()
        }
    }
}

fn main() {
    let mut auth_system: Authentication = Authentication::new();

    auth_system.register_user("user1".to_string(), "password123".to_string());

    let login_result: String = auth_system.login_user("user1".to_string(), "password123".to_string());
