import datetime as dt
from typing import Dict, List, Tuple

# Data structures
projects: Dict[str, str] = {}  # Project names
time_records: Dict[str, List[Tuple[dt.datetime, dt.datetime]]] = {}  # Project time records

def add_project(project_name: str) -> None:
    if project_name in projects:
        print(f"Error: Project '{project_name}' already exists.")
        return
    projects[project_name] = project_name
    time_records[project_name] = []
    print(f"Project '{project_name}' added successfully.")

def start_time(project_name: str, time_str: str) -> None:
    if project_name not in projects:
        print(f"Error: Project '{project_name}' does not exist.")
        return

    try:
        hours, minutes = map(int, time_str.split(':'))
        if not (0 <= hours < 24 and 0 <= minutes < 60):
            raise ValueError
        start_datetime = dt.datetime.now().replace(hour=hours, minute=minutes, second=0, microsecond=0)

        time_records[project_name].append((start_datetime, None))
        print(f"Start time {time_str} recorded for project '{project_name}'.")
    except ValueError:
        print("Error: Invalid time format. Please use HH:MM in 24-hour format.")

def stop_time(project_name: str, time_str: str) -> None:
    if project_name not in projects:
        print(f"Error: Project '{project_name}' does not exist.")
        return

    if not time_records[project_name] or time_records[project_name][-1][1] is not None:
        print(f"Error: No active time session for project '{project_name}'.")
        return

    try:
        hours, minutes = map(int, time_str.split(':'))
        if not (0 <= hours < 24 and 0 <= minutes < 60):
            raise ValueError
        stop_datetime = dt.datetime.now().replace(hour=hours, minute=minutes, second=0, microsecond=0)

        start_datetime = time_records[project_name][-1][0]
        if stop_datetime < start_datetime:
            print("Error: Stop time cannot be earlier than start time.")
            return

        time_records[project_name][-1] = (start_datetime, stop_datetime)
        print(f"Stop time {time_str} recorded for project '{project_name}'.")
    except ValueError:
        print("Error: Invalid time format. Please use HH:MM in 24-hour format.")

def generate_report(project_name: str) -> None:
    if project_name not in projects:
        print(f"Error: Project '{project_name}' does not exist.")
        return

    if not time_records[project_name]:
        print(f"No time records found for project '{project_name}'.")
        return

    total_minutes = 0
    incomplete_sessions = 0

    for start_time, end_time in time_records[project_name]:
        if end_time is None:
            incomplete_sessions += 1
            continue

        duration = end_time - start_time
        total_minutes += duration.total_seconds() // 60

    hours = int(total_minutes // 60)
    minutes = int(total_minutes % 60)

    print(f"Time spent on project '{project_name}': {hours} hours and {minutes} minutes.")
    if incomplete_sessions > 0:
        print(f"Note: {incomplete_sessions} session(s) without stop time were excluded.")

def main():
    print("Time Tracker Application")
    print("Available commands:")
    print("  ADD_PROJECT project_name")
    print("  START_TIME project_name time")
    print("  STOP_TIME project_name time")
    print("  REPORT project_name")
    print("  EXIT")

    while True:
        command = input("\nEnter command: ").strip().split()

        if not command:
            print("Please enter a valid command.")
            continue

        action = command[0].upper()

        if action == "ADD_PROJECT" and len(command) == 2:
            add_project(command[1])
        elif action == "START_TIME" and len(command) == 3:
            start_time(command[1], command[2])
        elif action == "STOP_TIME" and len(command) == 3:
            stop_time(command[1], command[2])
        elif action == "REPORT" and len(command) == 2:
            generate_report(command[1])
        elif action == "EXIT":
            print("Exiting Time Tracker. Goodbye!")
            break
        else:
            print("Invalid command. Please try again.")

if __name__ == "__main__":
    main()
