function manageTemperatureRecords() {
  const records = {};

  return {
    addRecord(location, temperature) {
      const date = new Date().toISOString();

      if (!records[location]) {
        records[location] = [];
      }

      records[location].push({ date, temperature });
      return { success: true, message: "Record added successfully" };
    },

    getAverage(location) {
      if (!records[location]) {
        return { success: false, message: "Location does not exist" };
      }

      if (records[location].length === 0) {
        return { success: false, message: "No records available to calculate average" };
      }

      const sum = records[location].reduce((total, record) => total + record.temperature, 0);
      const average = sum / records[location].length;

      return { success: true, average };
    },

    removeRecord(location, date) {
      if (!records[location]) {
        return { success: false, message: "Location does not exist" };
      }

      const initialLength = records[location].length;
      records[location] = records[location].filter(record => record.date !== date);

      if (records[location].length === initialLength) {
        return { success: false, message: "Record not found" };
      }

      return { success: true, message: "Record removed successfully" };
    },

    updateRecord(location, date, newTemperature) {
      if (!records[location]) {
        return { success: false, message: "Location does not exist" };
      }

      const recordIndex = records[location].findIndex(record => record.date === date);

      if (recordIndex === -1) {
        return { success: false, message: "Record not found" };
      }

      records[location][recordIndex].temperature = newTemperature;
      return { success: true, message: "Record updated successfully" };
    }
  };
}
