use std::collections::HashMap;
use std::path::Path;

struct FileSystem {
    files: HashMap<String, String>,
}

impl FileSystem {
    pub fn new() -> Self {
        FileSystem {
            files: HashMap::new(),
        }
    }

    pub fn create_file(&mut self, path: &str, content: &str) -> Result<(), String> {
        if self.files.contains_key(path) {
            return Err(format!("File already exists at path: {}", path));
        }
        self.files.insert(path.to_string(), content.to_string());
        Ok(())
    }

    pub fn read_file(&self, path: &str) -> Result<String, String> {
        match self.files.get(path) {
            Some(content) => Ok(content.clone()),
            None => Err(format!("File not found at path: {}", path)),
        }
    }

    pub fn update_file(&mut self, path: &str, new_content: &str) -> Result<(), String> {
        if !self.files.contains_key(path) {
            return Err(format!("File not found at path: {}", path));
        }
        self.files.insert(path.to_string(), new_content.to_string());
        Ok(())
    }

    pub fn delete_file(&mut self, path: &str) -> Result<(), String> {
        if !self.files.contains_key(path) {
            return Err(format!("File not found at path: {}", path));
        }
        self.files.remove(path);
        Ok(())
    }

    fn is_valid_path(&self, path: &str) -> bool {
        Path::new(path).is_absolute()
    }

    fn normalize_path(&self, path: &str) -> String {
        path.replace("\\", "/")
    }
}

fn main() {
    let mut fs = FileSystem::new();

    // Example usage
    fs.create_file("/documents/note.txt", "Hello, world!").unwrap();
    println!("{}", fs.read_file("/documents/note.txt").unwrap());
    fs.update_file("/documents/note.txt", "Updated content").unwrap();
    println!("{}", fs.read_file("/documents/note.txt").unwrap());
    fs.delete_file("/documents/note.txt").unwrap();
}
