#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Process {
    char name[50];
    int priority;
    struct Process* next;
} Process;

Process* head = NULL;

void add_process(char* name, int priority);
void kill_process(char* name);
void kill_priority(int priority);
void list_processes();
void free_all_processes();

int main() {
    char command[20];
    char name[50];
    int priority;
    int running;

    running = 1;

    printf("Process Manager started. Enter commands:\n");

    while (running) {
        printf("> ");
        scanf("%s", command);

        if (strcmp(command, "ADD") == 0) {
            scanf("%s %d", name, &priority);
            add_process(name, priority);
        } else if (strcmp(command, "KILL") == 0) {
            scanf("%s", name);
            kill_process(name);
        } else if (strcmp(command, "KILL_PRIORITY") == 0) {
            scanf("%d", &priority);
            kill_priority(priority);
        } else if (strcmp(command, "LIST") == 0) {
            list_processes();
        } else if (strcmp(command, "EXIT") == 0) {
            running = 0;
        } else {
            printf("Unknown command\n");
        }
    }

    free_all_processes();
    return 0;
}

void add_process(char* name, int priority) {
    Process* new_process;
    Process* current;
    Process* prev;

    new_process = (Process*)malloc(sizeof(Process));

    if (new_process == NULL) {
        printf("Memory allocation failed\n");
        return;
    }

    strcpy(new_process->name, name);
    new_process->priority = priority;
    new_process->next = NULL;

    if (head == NULL) {
        head = new_process;
        printf("Process %s added with priority %d\n", name, priority);
        return;
    }

    current = head;
    prev = NULL;

    while (current != NULL && current->priority <= priority) {
        prev = current;
        current = current->next;
    }

    if (prev == NULL) {
        new_process->next = head;
        head = new_process;
    } else {
        prev->next = new_process;
        new_process->next = current;
    }

    printf("Process %s added with priority %d\n", name, priority);
}

void kill_process(char* name) {
    Process* current;
    Process* prev;
    int found;

    if (head == NULL) {
        printf("No processes to kill\n");
        return;
    }

    current = head;
    prev = NULL;
    found = 0;

    while (current != NULL) {
        if (strcmp(current->name, name) == 0) {
            if (prev == NULL) {
                head = current->next;
            } else {
                prev->next = current->next;
            }

            printf("Process %s terminated\n", name);
            free(current);
            found = 1;
            break;
        }

        prev = current;
        current = current->next;
    }

    if (!found) {
        printf("Process %s not found\n", name);
    }
}

void kill_priority(int priority) {
    Process* current;
    Process* prev;
    Process* temp;
    int count;

    if (head == NULL) {
        printf("No processes to kill\n");
        return;
    }

    current = head;
    prev = NULL;
    count = 0;

    while (current != NULL) {
        if (current->priority == priority) {
            temp = current;

            if (prev == NULL) {
                head = current->next;
                current = head;
            } else {
                prev->next = current->next;
                current = prev->next;
            }

            free(temp);
            count++;
        } else {
            prev = current;
            current = current->next;
        }
    }

    if (count > 0) {
        printf("Terminated %d processes with priority %d\n", count, priority);
    } else {
        printf("No processes found with priority %d\n", priority);
    }
}

void list_processes() {
    Process* current;
    int count;

    if (head == NULL) {
        printf("No processes running\n");
        return;
    }

    printf("Process List (sorted by priority):\n");
    printf("Priority\tName\n");
    printf("------------------------\n");

    current = head;
    count = 0;

    while (current != NULL) {
        printf("%d\t\t%s\n", current->priority, current->name);
        current = current->next;
        count++;
    }

    printf("------------------------\n");
    printf("Total: %d processes\n", count);
}

void free_all_processes() {
    Process* current;
    Process* next;

    current = head;

    while (current != NULL) {
        next = current->next;
        free(current);
        current = next;
    }

    head = NULL;
}
