import javax.swing.*;
import java.awt.*;
import java.awt.event.ActionEvent;
import java.awt.event.ActionListener;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class Calculator extends JFrame {
    private final JTextField firstNumberField;
    private final JTextField secondNumberField;
    private final JTextField resultField;
    private final JButton addButton;
    private final JButton subtractButton;
    private final JButton multiplyButton;
    private final JButton divideButton;
    private final Lock calculationLock;
    private final ExecutorService calculationExecutor;

    public Calculator() {
        setTitle("Basic Calculator");
        setSize(400, 200);
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        setLayout(new GridLayout(5, 2, 10, 10));

        add(new JLabel("First Number:"));
        firstNumberField = new JTextField();
        add(firstNumberField);

        add(new JLabel("Second Number:"));
        secondNumberField = new JTextField();
        add(secondNumberField);

        add(new JLabel("Result:"));
        resultField = new JTextField();
        resultField.setEditable(false);
        add(resultField);

        addButton = new JButton("Add");
        subtractButton = new JButton("Subtract");
        multiplyButton = new JButton("Multiply");
        divideButton = new JButton("Divide");

        add(addButton);
        add(subtractButton);
        add(multiplyButton);
        add(divideButton);

        calculationLock = new ReentrantLock();
        calculationExecutor = Executors.newSingleThreadExecutor();

        addButton.addActionListener(new CalculationActionListener(OperationType.ADD));
        subtractButton.addActionListener(new CalculationActionListener(OperationType.SUBTRACT));
        multiplyButton.addActionListener(new CalculationActionListener(OperationType.MULTIPLY));
        divideButton.addActionListener(new CalculationActionListener(OperationType.DIVIDE));

        setVisible(true);
    }

    private enum OperationType {
        ADD, SUBTRACT, MULTIPLY, DIVIDE
    }

    private class CalculationActionListener implements ActionListener {
        private final OperationType operationType;

        public CalculationActionListener(OperationType operationType) {
            this.operationType = operationType;
        }

        @Override
        public void actionPerformed(ActionEvent e) {
            calculationExecutor.submit(() -> performCalculation(operationType));
        }
    }

    private void performCalculation(OperationType operationType) {
        calculationLock.lock();
        try {
            double firstNumber = Double.parseDouble(firstNumberField.getText());
            double secondNumber = Double.parseDouble(secondNumberField.getText());
            double result = 0;

            switch (operationType) {
                case ADD:
                    result = add(firstNumber, secondNumber);
                    break;
                case SUBTRACT:
                    result = subtract(firstNumber, secondNumber);
                    break;
                case MULTIPLY:
                    result = multiply(firstNumber, secondNumber);
                    break;
                case DIVIDE:
                    result = divide(firstNumber, secondNumber);
                    break;
            }

            final double finalResult = result;
            SwingUtilities.invokeLater(() -> resultField.setText(String.valueOf(finalResult)));
        } catch (NumberFormatException e) {
            SwingUtilities.invokeLater(() -> resultField.setText("Invalid input"));
        } catch (ArithmeticException e) {
            SwingUtilities.invokeLater(() -> resultField.setText(e.getMessage()));
        } finally {
            calculationLock.unlock();
        }
    }

    public double add(double firstNumber, double secondNumber) {
        return firstNumber + secondNumber;
    }

    public double subtract(double firstNumber, double secondNumber) {
        return firstNumber - secondNumber;
    }

    public double multiply(double firstNumber, double secondNumber) {
        return firstNumber * secondNumber;
    }

    public double divide(double firstNumber, double secondNumber) {
        if (secondNumber == 0) {
            throw new ArithmeticException("Division by zero");
        }
        return firstNumber / secondNumber;
    }

    public static void main(String[] args) {
        SwingUtilities.invokeLater(Calculator::new);
    }
}
