    /// 
    /// # Parameters
    /// * `name` - The name of the event to remove
    /// 
    /// # Returns
    /// * `Result<(), String>` - Ok if the event was removed, Err with message if event doesn't exist
    pub fn remove_event(&mut self, name: String) -> Result<(), String> {
