```javascript
/**
 * Manages todo tasks with operations for adding, completing, deleting, and listing tasks.
 * @param {string} command - The operation to perform (add, complete, delete, list)
 * @param {string|number} argument - The task description or task ID
 * @returns {string} Result message or task list
 */
function manageTodos(command, argument) {
  // Create a closure to maintain state between function calls
  const todoState = {
    tasks: [],
    lastId: 0
  };

  // Return the actual function that will be executed
  return function(command, argument) {
    const commandString = String(command).toLowerCase();

    // Validate command
    if (!['add', 'complete', 'delete', 'list'].includes(commandString)) {
      return "Error: Invalid command. Use 'add', 'complete', 'delete', or 'list'.";
    }

    // Process commands
    if (commandString === 'add') {
      if (!argument || typeof argument !== 'string' || argument.trim() === '') {
        return "Error: Task description is required.";
      }

      const taskId = todoState.lastId + 1;
      const taskDescription = String(argument).trim();
      const taskCompleted = false;

      todoState.tasks.push({
        task_id: taskId,
        description: taskDescription,
        completed: taskCompleted
      });

      todoState.lastId = taskId;
      return `Task added with ID: ${taskId}`;
    }

    else if (commandString === 'complete') {
      const taskId = Number(argument);

      if (isNaN(taskId)) {
        return "Error: Task ID must be a number.";
      }

      const taskIndex = todoState.tasks.findIndex(task => task.task_id === taskId);

      if (taskIndex === -1) {
        return `Error: Task with ID ${taskId} does not exist.`;
      }

      todoState.tasks[taskIndex].completed = true;
      return `Task ${taskId} marked as completed.`;
    }

    else if (commandString === 'delete') {
      const taskId = Number(argument);

      if (isNaN(taskId)) {
        return "Error: Task ID must be a number.";
      }

      const taskIndex = todoState.tasks.findIndex(task => task.task_id === taskId);

      if (taskIndex === -1) {
        return `Error: Task with ID ${taskId} does not exist.`;
      }

      todoState.tasks.splice(taskIndex, 1);
      return `Task ${taskId} deleted.`;
    }

    else if (commandString === 'list') {
      if (todoState.tasks.length === 0) {
        return "No tasks found.";
      }

      let taskListOutput = "Tasks:\n";
      for (let i = 0; i < todoState.tasks.length; i++) {
        const task = todoState.tasks[i];
        const statusText = task.completed ? "Completed" : "Pending";
        taskListOutput += `${task.task_id}. ${task.description} - ${statusText}\n`;
      }

      return taskListOutput.trim();
    }
  };
}

// Create a todo manager instance
const todoManager = manageTodos();
