public class TrafficLight {
    // Constants for light timings (in seconds)
    private static final int GREEN_LIGHT_DURATION = 30;
    private static final int YELLOW_LIGHT_DURATION = 5;
    private static final int RED_LIGHT_DURATION = 20;
    private static final String INITIAL_LIGHT_COLOR = "Red";

    // Instance variables
    private String currentLightColor;
    private int currentDelay;

    /**
     * Constructor initializes the traffic light with default values
     */
    public TrafficLight() {
        this.currentLightColor = INITIAL_LIGHT_COLOR;
        this.currentDelay = getDefaultDelayForColor(INITIAL_LIGHT_COLOR);
    }

    /**
     * Changes the current light to the specified color
     * @param color The new traffic light color
     */
    public void changeLight(String color) {
        if (isValidColor(color)) {
            this.currentLightColor = color;
            this.currentDelay = getDefaultDelayForColor(color);
        } else {
            System.out.println("Invalid light color: " + color);
        }
    }

    /**
     * Returns the current color of the traffic light
     * @return The current light color
     */
    public String getCurrentLight() {
        return this.currentLightColor;
    }

    /**
     * Sets a custom delay for the current light
     * @param seconds The delay in seconds
     */
    public void addDelay(int seconds) {
        if (seconds > 0) {
            this.currentDelay = seconds;
        } else {
            System.out.println("Delay must be a positive number of seconds");
        }
    }

    /**
     * Automatically updates the traffic light to the next color
     * in the sequence: Red -> Green -> Yellow -> Red
     */
    public void nextLight() {
        switch (this.currentLightColor) {
            case "Red":
                changeLight("Green");
                break;
            case "Green":
                changeLight("Yellow");
                break;
            case "Yellow":
                changeLight("Red");
                break;
            default:
                // Reset to a valid state if somehow in an invalid state
                changeLight("Red");
                break;
        }
    }

    /**
     * Checks if the provided color is valid
     * @param color The color to validate
     * @return True if the color is valid, false otherwise
     */
    private boolean isValidColor(String color) {
        return color.equals("Red") || color.equals("Green") || color.equals("Yellow");
    }

    /**
     * Returns the default delay time for a given light color
     * @param color The light color
     * @return The default delay in seconds for the given color
     */
    private int getDefaultDelayForColor(String color) {
        switch (color) {
            case "Red":
                return RED_LIGHT_DURATION;
            case "Green":
                return GREEN_LIGHT_DURATION;
            case "Yellow":
                return YELLOW_LIGHT_DURATION;
            default:
                return 0;
        }
    }
}
