#define MAX_SETTINGS 100
#define MAX_NAME_LENGTH 50
#define MAX_VALUE_LENGTH 100

// Structure to hold a setting
typedef struct {
    char name[MAX_NAME_LENGTH];
    char value[MAX_VALUE_LENGTH];
    char default_value[MAX_VALUE_LENGTH];
} Setting;

// Function declarations
void processCommand(const char* command);
void setSetting(const char* setting_name, const char* setting_value);
void getSetting(const char* setting_name);
void resetSetting(const char* setting_name);
