int setting_count = 0;

int main() {
    char command[200];

    // Initialize with some default settings
    strcpy(settings[0].name, "theme");
    strcpy(settings[0].value, "dark");
    strcpy(settings[0].default_value, "light");

    strcpy(settings[1].name, "font_size");
    strcpy(settings[1].value, "12");
    strcpy(settings[1].default_value, "10");

    strcpy(settings[2].name, "notifications");
    strcpy(settings[2].value, "on");
    strcpy(settings[2].default_value, "off");

    setting_count = 3;

    printf("Settings Manager\n");
    printf("Available commands:\n");
    printf("SET setting_name setting_value\n");
    printf("GET setting_name\n");
    printf("RESET setting_name\n");
    printf("LIST_ALL\n");
    printf("EXIT\n\n");

    while (1) {
        printf("> ");
        fgets(command, sizeof(command), stdin);
        command[strcspn(command, "\n")] = 0; // Remove newline

        if (strcmp(command, "EXIT") == 0) {
            break;
        }

        processCommand(command);
    }

    return 0;
}

void processCommand(const char* command) {
    char cmd[10];
    char setting_name[MAX_NAME_LENGTH];
    char setting_value[MAX_VALUE_LENGTH];
    int result;

    result = sscanf(command, "%s %s %[^\n]", cmd, setting_name, setting_value);

    if (strcmp(cmd, "SET") == 0) {
        if (result < 3) {
            printf("Error: SET command requires both setting name and value\n");
            return;
        }
        setSetting(setting_name, setting_value);
    } else if (strcmp(cmd, "GET") == 0) {
        if (result < 2) {
            printf("Error: GET command requires setting name\n");
            return;
        }
        getSetting(setting_name);
    } else if (strcmp(cmd, "RESET") == 0) {
        if (result < 2) {
            printf("Error: RESET command requires setting name\n");
            return;
        }
        resetSetting(setting_name);
    } else if (strcmp(cmd, "LIST_ALL") == 0) {
        listAllSettings();
    } else {
        printf("Error: Unknown command '%s'\n", cmd);
    }
}

void setSetting(const char* setting_name, const char* setting_value) {
    int index;

    index = findSetting(setting_name);

    if (index != -1) {
        // Update existing setting
        strcpy(settings[index].value, setting_value);
        printf("Updated setting '%s' to '%s'\n", setting_name, setting_value);
    } else if (setting_count < MAX_SETTINGS) {
        // Add new setting
        strcpy(settings[setting_count].name, setting_name);
        strcpy(settings[setting_count].value, setting_value);
        strcpy(settings[setting_count].default_value, setting_value); // Default is initial value
        setting_count++;
        printf("Added new setting '%s' with value '%s'\n", setting_name, setting_value);
    } else {
        printf("Error: Maximum number of settings reached\n");
    }
}

void getSetting(const char* setting_name) {
    int index;

    index = findSetting(setting_name);

    if (index != -1) {
        printf("%s = %s\n", setting_name, settings[index].value);
    } else {
        printf("Error: Setting '%s' not found\n", setting_name);
    }
}

void resetSetting(const char* setting_name) {
    int index;

    index = findSetting(setting_name);

    if (index != -1) {
        strcpy(settings[index].value, settings[index].default_value);
        printf("Reset '%s' to default value '%s'\n", setting_name, settings[index].default_value);
    } else {
        printf("Error: Setting '%s' not found\n", setting_name);
    }
}

void listAllSettings() {
    int i;

    if (setting_count == 0) {
        printf("No settings available\n");
        return;
    }

    printf("Current settings:\n");
    for (i = 0; i < setting_count; i++) {
        printf("%s = %s (default: %s)\n", settings[i].name, settings[i].value, settings[i].default_value);
    }
}

int findSetting(const char* setting_name) {
    int i;

    for (i = 0; i < setting_count; i++) {
        if (strcmp(settings[i].name, setting_name) == 0) {
            return i;
        }
    }

    return -1; // Not found
}
