                    print(f"Added {name} with phone number {phone_number}")

            elif command == "SEARCH":
                name = input("Enter name to search: ").strip()
                if name in contacts:
                    print(f"{name}'s phone number: {contacts[name]}")
                else:
                    print(f"Contact {name} not found.")

