```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <pthread.h>
#include <unistd.h>

#define MAX_TASKS 100
#define MAX_NAME_LENGTH 50

typedef enum {
    WAITING,
    RUNNING,
    COMPLETED,
    CANCELLED
} TaskStatus;

typedef struct {
    char name[MAX_NAME_LENGTH];
    int duration;
    TaskStatus status;
    pthread_t thread;
    int exists;
} Task;

// Global variables
Task task_list[MAX_TASKS];
int task_count = 0;
pthread_mutex_t task_mutex = PTHREAD_MUTEX_INITIALIZER;

// Function prototypes
void add_task(const char* task_name, int duration);
void start_task(const char* task_name);
void check_task(const char* task_name);
void cancel_task(const char* task_name);
void* task_execution(void* arg);
int find_task_index(const char* task_name);

// Task execution thread function
void* task_execution(void* arg) {
    int index = *((int*)arg);
    free(arg);

    sleep(task_list[index].duration);

    pthread_mutex_lock(&task_mutex);
    if (task_list[index].status == RUNNING) {
        task_list[index].status = COMPLETED;
    }
    pthread_mutex_unlock(&task_mutex);

    return NULL;
}

// Find task by name and return its index
int find_task_index(const char* task_name) {
    for (int i = 0; i < task_count; i++) {
        if (task_list[i].exists && strcmp(task_list[i].name, task_name) == 0) {
            return i;
        }
    }
    return -1;
}

// Add a new task to the system
void add_task(const char* task_name, int duration) {
    pthread_mutex_lock(&task_mutex);

    if (task_count >= MAX_TASKS) {
        printf("Error: Maximum task limit reached\n");
        pthread_mutex_unlock(&task_mutex);
        return;
    }

    if (find_task_index(task_name) != -1) {
        printf("Error: Task '%s' already exists\n", task_name);
        pthread_mutex_unlock(&task_mutex);
        return;
    }

    strcpy(task_list[task_count].name, task_name);
    task_list[task_count].duration = duration;
    task_list[task_count].status = WAITING;
    task_list[task_count].exists = 1;

    printf("Task '%s' added with duration %d seconds\n", task_name, duration);
    task_count++;

    pthread_mutex_unlock(&task_mutex);
}

// Start a task by its name
void start_task(const char* task_name) {
    pthread_mutex_lock(&task_mutex);

    int index = find_task_index(task_name);
    if (index == -1) {
        printf("Error: Task '%s' not found\n", task_name);
        pthread_mutex_unlock(&task_mutex);
        return;
    }

    if (task_list[index].status != WAITING) {
        printf("Error: Task '%s' is not in waiting state\n", task_name);
        pthread_mutex_unlock(&task_mutex);
        return;
    }

    task_list[index].status = RUNNING;
    printf("Task '%s' started\n", task_name);

    int* arg = malloc(sizeof(int));
    *arg = index;

    if (pthread_create(&task_list[index].thread, NULL, task_execution, arg) != 0) {
        printf("Error: Failed to start task thread\n");
        task_list[index].status = WAITING;
        free(arg);
    }

    pthread_mutex_unlock(&task_mutex);
}

// Check the status of a task
void check_task(const char* task_name) {
    pthread_mutex_lock(&task_mutex);

    int index = find_task_index(task_name);
    if (index == -1) {
        printf("Error: Task '%s' not found\n", task_name);
        pthread_mutex_unlock(&task_mutex);
        return;
    }

    const char* status_str;
    switch(task_list[index].status) {
        case WAITING:   status_str = "waiting"; break;
        case RUNNING:   status_str = "running"; break;
        case COMPLETED: status_str = "completed"; break;
        case CANCELLED: status_str = "cancelled"; break;
        default:        status_str = "unknown";
    }

    printf("Task '%s' status: %s\n", task_name, status_str);

    pthread_mutex_unlock(&task_mutex);
}

// Cancel a task
void cancel_task(const char* task_name) {
    pthread_mutex_lock(&task_mutex);

    int index = find_task_index(task_name);
    if (index == -1) {
        printf("Error: Task '%s' not found\n", task_name);
        pthread_mutex_unlock(&task_mutex);
        return;
    }

    if (task_list[index].status != WAITING && task_list[index].status != RUNNING) {
        printf("Error: Cannot cancel task '%s' that is not waiting or running\n", task_name);
        pthread_mutex_unlock(&task_mutex);
        return;
    }

    if (task_list[index].status == RUNNING) {
        pthread_cancel(task_list[index].thread);
        pthread_join(task_list[index].thread, NULL);
    }

    task_list[index].status = CANCELLED;
    printf("Task '%s' cancelled\n", task_name);

    pthread_mutex_unlock(&task_mutex);
}

int main() {
    char command[20];
    char task_name[MAX_NAME_LENGTH];
    int duration;

    printf("Task Scheduler System\n");
    printf("Commands: ADD_TASK, START_TASK, CHECK_TASK, CANCEL_TASK, EXIT\n");

    while (1) {
        printf("\n> ");
        scanf("%s", command);

        if (strcmp(command, "ADD_TASK") == 0) {
            scanf("%s %d", task_name, &duration);
            add_task(task_name, duration);
        } 
        else if (strcmp(command, "START_TASK") == 0) {
            scanf("%s", task_name);
            start_task(task_name);
        } 
        else if (strcmp(command, "CHECK_TASK") == 0) {
            scanf("%s", task_name);
            check_task(task_name);
        } 
        else if (strcmp(command, "CANCEL_TASK") == 0) {
            scanf("%s", task_name);
            cancel_task(task_name);
        } 
        else if (strcmp(command, "EXIT") == 0) {
            break;
        } 
        else {
            printf("Unknown command\n");
        }
    }

    // Clean up
    pthread_mutex_destroy(&task_mutex);
    return 0;
}
