Here's the `FileManager` class in C++ designed to manage text file operations:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <filesystem>

class FileManager {
public:
    FileManager() : isFileOpen(false) {}

    ~FileManager() {
        if (isFileOpen) {
            closeFile();
        }
    }

    bool openFile(std::string fileName) {
        if (isFileOpen) {
            std::cerr << "Error: A file is already open. Please close it first." << std::endl;
            return false;
        }

        if (!std::filesystem::exists(fileName)) {
            std::cerr << "Error: File '" << fileName << "' does not exist." << std::endl;
            return false;
        }

        fileStream.open(fileName, std::ios::in | std::ios::out);

        if (!fileStream.is_open()) {
            std::cerr << "Error: Failed to open file '" << fileName << "'." << std::endl;
            return false;
        }

        currentFileName = fileName;
        isFileOpen = true;
        return true;
    }

    bool writeFile(std::string data) {
        if (!isFileOpen) {
            std::cerr << "Error: No file is currently open." << std::endl;
            return false;
        }

        fileStream.clear();
        fileStream.seekp(0);
        fileStream << data;

        if (fileStream.fail()) {
            std::cerr << "Error: Failed to write to file '" << currentFileName << "'." << std::endl;
            return false;
        }

        return true;
    }

    std::string readFile() {
        if (!isFileOpen) {
            std::cerr << "Error: No file is currently open." << std::endl;
            return "";
        }

        std::string content;
        std::string line;

        fileStream.clear();
        fileStream.seekg(0);

        while (std::getline(fileStream, line)) {
            content += line + "\n";
        }

        if (fileStream.fail() && !fileStream.eof()) {
            std::cerr << "Error: Failed to read from file '" << currentFileName << "'." << std::endl;
            return "";
        }

        return content;
    }

    bool closeFile() {
        if (!isFileOpen) {
            std::cerr << "Error: No file is currently open." << std::endl;
            return false;
        }

        fileStream.close();
        isFileOpen = false;
        currentFileName = "";
        return true;
    }

protected:
    std::string currentFileName;

private:
    std::fstream fileStream;
    bool isFileOpen;
};
