use std::io::{self, Write};

fn main() {
    println!("Welcome to the Rust Calculator");
    println!("Supported operations: ADD, SUBTRACT, MULTIPLY, DIVIDE");
    println!("Example: ADD 5 3");

    loop {
        print!("> ");
        io::stdout().flush().unwrap();

        let mut input: String = String::new();
        io::stdin().read_line(&mut input).unwrap();

        let input: String = input.trim().to_string();

        if input.to_lowercase() == "exit" || input.to_lowercase() == "quit" {
            break;
        }

        let parts: Vec<&str> = input.split_whitespace().collect();

        if parts.len() != 3 {
            println!("Invalid input format. Please use: OPERATION NUM1 NUM2");
            continue;
        }

        let operation: &str = parts[0];

        let num1: i32 = match parts[1].parse() {
            Ok(num) => num,
            Err(_) => {
                println!("Error: First number is not a valid integer.");
                continue;
            }
        };

        let num2: i32 = match parts[2].parse() {
            Ok(num) => num,
            Err(_) => {
                println!("Error: Second number is not a valid integer.");
                continue;
            }
        };

        match operation.to_uppercase().as_str() {
            "ADD" => {
                let result: i32 = add(num1, num2);
                println!("Result: {}", result);
            },
            "SUBTRACT" => {
                let result: i32 = subtract(num1, num2);
                println!("Result: {}", result);
            },
            "MULTIPLY" => {
                let result: i32 = multiply(num1, num2);
                println!("Result: {}", result);
            },
            "DIVIDE" => {
                match divide(num1, num2) {
                    Ok(result) => println!("Result: {}", result),
                    Err(error) => println!("Error: {}", error),
                }
            },
            _ => println!("Unsupported operation. Please use ADD, SUBTRACT, MULTIPLY, or DIVIDE."),
        }
    }
}

fn add(num1: i32, num2: i32) -> i32 {
    let result: i32 = num1 + num2;
    return result;
}

fn subtract(num1: i32, num2: i32) -> i32 {
    let result: i32 = num1 - num2;
    return result;
}

fn multiply(num1: i32, num2: i32) -> i32 {
    let result: i32 = num1 * num2;
    return result;
}

fn divide(num1: i32, num2: i32) -> Result<f64, String> {
    if num2 == 0 {
        return Err(String::from("Division by zero is not allowed"));
    }

    let result: f64 = num1 as f64 / num2 as f64;
    return Ok(result);
}
