function manageShoppingCart() {
  // Initialize an empty shopping cart object
  const cart = {};

  // Return an object with methods to manipulate the shopping cart
  return {
    /**
     * Adds a product with specified quantity to the shopping cart
     * @param {string|number} productId - The unique identifier for the product
     * @param {number} quantity - The quantity to add (must be positive)
     * @returns {object} - Status message indicating success
     */
    addProduct: function(productId, quantity) {
      // Validate inputs
      if (!productId) {
        return { success: false, message: "Product ID is required" };
      }

      const numQuantity = Number(quantity);
      if (isNaN(numQuantity) || numQuantity <= 0) {
        return { success: false, message: "Quantity must be a positive number" };
      }

      // Check if product exists in cart, otherwise add it
      if (cart[productId]) {
        cart[productId] += numQuantity;
      } else {
        cart[productId] = numQuantity;
      }

      return { success: true, message: "Product added to cart" };
    },

    /**
     * Removes a product from the shopping cart
     * @param {string|number} productId - The unique identifier for the product to remove
     * @returns {object} - Status message indicating success or failure
     */
    removeProduct: function(productId) {
      // Check if product exists in cart
      if (!cart[productId]) {
        return { success: false, message: "Product not found in cart" };
      }

      // Remove product from cart
      delete cart[productId];
      return { success: true, message: "Product removed from cart" };
    },

    /**
     * Updates the quantity of a specific product in the cart
     * @param {string|number} productId - The unique identifier for the product
     * @param {number} quantity - The new quantity (must be positive)
     * @returns {object} - Status message indicating success or failure
     */
    updateProduct: function(productId, quantity) {
      // Validate inputs
      if (!cart[productId]) {
        return { success: false, message: "Product not found in cart" };
      }

      const numQuantity = Number(quantity);
      if (isNaN(numQuantity) || numQuantity <= 0) {
        return { success: false, message: "Quantity must be a positive number" };
      }

      // Update product quantity
      cart[productId] = numQuantity;
      return { success: true, message: "Product quantity updated" };
    },

    /**
     * Retrieves the quantity of a product in the cart
     * @param {string|number} productId - The unique identifier for the product
     * @returns {object} - Object containing quantity or error message
     */
    getProduct: function(productId) {
      // Check if product exists in cart
      if (!cart[productId]) {
        return { success: false, message: "Product not found in cart" };
      }

      return { 
        success: true, 
        productId: productId, 
        quantity: cart[productId] 
      };
    }
  };
