import java.util.ArrayList;

public class EmailManager {
    private ArrayList<String> subscriptions;

    public EmailManager() {
        subscriptions = new ArrayList<>();
    }

    /**
     * Adds a new email address to the subscription list.
     * 
     * @param emailAddress The email address to subscribe
     * @return true if the subscription was successful, false if already subscribed
     */
    public boolean subscribe(String emailAddress) {
        if (emailAddress == null || emailAddress.isEmpty()) {
            throw new IllegalArgumentException("Email address cannot be null or empty");
        }

        if (isSubscribed(emailAddress)) {
            return false;
        }

        subscriptions.add(emailAddress);
        return true;
    }

    /**
     * Removes the email address from the subscription list if it exists.
     * 
     * @param emailAddress The email address to unsubscribe
     * @return true if the unsubscription was successful, false if not subscribed
     */
    public boolean unsubscribe(String emailAddress) {
        if (emailAddress == null || emailAddress.isEmpty()) {
            throw new IllegalArgumentException("Email address cannot be null or empty");
        }

        return subscriptions.remove(emailAddress);
    }

    /**
     * Returns an ArrayList of all subscribed email addresses.
     * 
     * @return ArrayList containing all subscribed email addresses
     */
    public ArrayList<String> listSubscriptions() {
        return new ArrayList<>(subscriptions);
    }

    /**
     * Checks whether an email address is already subscribed.
     * 
     * @param emailAddress The email address to check
     * @return true if subscribed, false otherwise
     */
    public boolean isSubscribed(String emailAddress) {
        if (emailAddress == null || emailAddress.isEmpty()) {
            throw new IllegalArgumentException("Email address cannot be null or empty");
        }

        return subscriptions.contains(emailAddress);
    }
