public class InventoryManagementSystem {
    // Constants
    private static final String ERROR_PRODUCT_NOT_FOUND = "Product not found in inventory";
    private static final String ERROR_INVALID_QUANTITY = "Invalid quantity value";
    private static final int MAX_PRODUCTS = 100;

    // Variables
    private String[] productNames;
    private int[] productQuantities;
    private int productCount;

    public InventoryManagementSystem() {
        productNames = new String[MAX_PRODUCTS];
        productQuantities = new int[MAX_PRODUCTS];
        productCount = 0;
    }

    public void addProduct(String name, int quantity) {
        if (quantity < 0) {
            System.out.println(ERROR_INVALID_QUANTITY);
            return;
        }

        // Check if product already exists
        for (int i = 0; i < productCount; i++) {
            if (productNames[i].equals(name)) {
                productQuantities[i] += quantity;
                return;
            }
        }

        // Add new product if capacity allows
        if (productCount < MAX_PRODUCTS) {
            productNames[productCount] = name;
            productQuantities[productCount] = quantity;
            productCount++;
        } else {
            System.out.println("Inventory is full. Cannot add more products.");
        }
    }

    public void removeProduct(String name) {
        for (int i = 0; i < productCount; i++) {
            if (productNames[i].equals(name)) {
                // Remove by shifting all elements
                for (int j = i; j < productCount - 1; j++) {
                    productNames[j] = productNames[j + 1];
                    productQuantities[j] = productQuantities[j + 1];
                }
                productCount--;
                return;
            }
        }

        System.out.println(ERROR_PRODUCT_NOT_FOUND);
    }

    public int getProductQuantity(String name) {
        for (int i = 0; i < productCount; i++) {
            if (productNames[i].equals(name)) {
                return productQuantities[i];
            }
        }

        return 0;
    }

    public void updateProductQuantity(String name, int newQuantity) {
        if (newQuantity < 0) {
            System.out.println(ERROR_INVALID_QUANTITY);
            return;
        }

        for (int i = 0; i < productCount; i++) {
            if (productNames[i].equals(name)) {
                productQuantities[i] = newQuantity;
                return;
            }
        }
    }

    public static void main(String[] args) {
        InventoryManagementSystem inventory = new InventoryManagementSystem();

        // Example usage
        inventory.addProduct("Laptop", 10);
        inventory.addProduct("Smartphone", 20);
        inventory.addProduct("Tablet", 15);

        System.out.println("Laptop quantity: " + inventory.getProductQuantity("Laptop"));

        inventory.updateProductQuantity("Laptop", 12);
        System.out.println("Updated laptop quantity: " + inventory.getProductQuantity("Laptop"));

        inventory.removeProduct("Tablet");
        System.out.println("Tablet quantity after removal: " + inventory.getProductQuantity("Tablet"));
    }
}
