I'll create a C client-server application using TCP sockets for fetching system statistics as specified.

First, let's create the server implementation:

```c:server.c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <sys/statvfs.h>
#include <sys/sysinfo.h>

#define PORT 8080
#define BUFFER_SIZE 1024

// Function prototypes
float get_cpu_usage(void);
float get_memory_usage(void);
float get_disk_usage(void);
void handle_client_request(int client_socket);

int main(int argc, char *argv[]) {
    int server_fd, client_socket;
    struct sockaddr_in address;
    int addrlen = sizeof(address);
    int opt = 1;

    // Creating socket file descriptor
    if ((server_fd = socket(AF_INET, SOCK_STREAM, 0)) == 0) {
        perror("Socket creation failed");
        exit(EXIT_FAILURE);
    }

    // Set socket options
    if (setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt))) {
        perror("Setsockopt failed");
        exit(EXIT_FAILURE);
    }

    // Configure address structure
    address.sin_family = AF_INET;
    address.sin_addr.s_addr = INADDR_ANY;
    address.sin_port = htons(PORT);

    // Bind the socket to the port
    if (bind(server_fd, (struct sockaddr *)&address, sizeof(address)) < 0) {
        perror("Bind failed");
        exit(EXIT_FAILURE);
    }

    // Start listening for connections
    if (listen(server_fd, 3) < 0) {
        perror("Listen failed");
        exit(EXIT_FAILURE);
    }

    printf("Server started. Listening on port %d...\n", PORT);

    // Accept and handle connections
    while (1) {
        if ((client_socket = accept(server_fd, (struct sockaddr *)&address, (socklen_t*)&addrlen)) < 0) {
            perror("Accept failed");
            exit(EXIT_FAILURE);
        }

        printf("New client connected\n");

        handle_client_request(client_socket);

        close(client_socket);
        printf("Client disconnected\n");
    }

    return 0;
}

// Public methods

// Handle client requests
void handle_client_request(int client_socket) {
    char buffer[BUFFER_SIZE] = {0};
    int bytes_read;
    char response[BUFFER_SIZE];

    // Read the request from client
    bytes_read = read(client_socket, buffer, BUFFER_SIZE);
    if (bytes_read <= 0) {
        return;
    }

    buffer[bytes_read] = '\0';
    printf("Received request: %s\n", buffer);

    // Process the request based on command
    if (strcmp(buffer, "CPU_USAGE") == 0) {
        float cpu_usage = get_cpu_usage();
        snprintf(response, BUFFER_SIZE, "CPU Usage: %.2f%%", cpu_usage);
    } 
    else if (strcmp(buffer, "MEMORY_USAGE") == 0) {
        float memory_usage = get_memory_usage();
        snprintf(response, BUFFER_SIZE, "Memory Usage: %.2f%%", memory_usage);
    }
    else if (strcmp(buffer, "DISK_USAGE") == 0) {
        float disk_usage = get_disk_usage();
        snprintf(response, BUFFER_SIZE, "Disk Usage: %.2f%%", disk_usage);
    }
    else {
        snprintf(response, BUFFER_SIZE, "Unknown command");
    }

    // Send response back to client
    send(client_socket, response, strlen(response), 0);
}

// Private methods

// Get CPU usage percentage
float get_cpu_usage(void) {
    FILE *fp;
    char buffer[1024];
    unsigned long long user, nice, system, idle, iowait, irq, softirq, steal;
    unsigned long long total, idle_time, non_idle_time;
    float usage_percent = 0.0;

    // First measurement
    fp = fopen("/proc/stat", "r");
    if (fp == NULL) {
        return -1.0;
    }

    if (fgets(buffer, sizeof(buffer), fp)) {
        sscanf(buffer, "cpu %llu %llu %llu %llu %llu %llu %llu %llu", 
               &user, &nice, &system, &idle, &iowait, &irq, &softirq, &steal);
    }
    fclose(fp);

    idle_time = idle + iowait;
    non_idle_time = user + nice + system + irq + softirq + steal;
    total = idle_time + non_idle_time;

    // Sleep for a bit to get a difference
    usleep(100000); // 100ms

    // Second measurement
    fp = fopen("/proc/stat", "r");
    if (fp == NULL) {
        return -1.0;
    }

    unsigned long long user_prev = user, nice_prev = nice, system_prev = system, 
                      idle_prev = idle, iowait_prev = iowait, irq_prev = irq, 
                      softirq_prev = softirq, steal_prev = steal;
    unsigned long long total_prev = total, idle_time_prev = idle_time;

    if (fgets(buffer, sizeof(buffer), fp)) {
        sscanf(buffer, "cpu %llu %llu %llu %llu %llu %llu %llu %llu", 
               &user, &nice, &system, &idle, &iowait, &irq, &softirq, &steal);
    }
    fclose(fp);

    idle_time = idle + iowait;
    non_idle_time = user + nice + system + irq + softirq + steal;
    total = idle_time + non_idle_time;

    // Calculate the CPU usage percentage
    unsigned long long total_diff = total - total_prev;
    unsigned long long idle_diff = idle_time - idle_time_prev;

    if (total_diff > 0) {
        usage_percent = 100.0 * (total_diff - idle_diff) / total_diff;
    }

    return usage_percent;
}

// Get memory usage percentage
float get_memory_usage(void) {
    struct sysinfo info;

    if (sysinfo(&info) != 0) {
        return -1.0;
    }

    unsigned long total_ram = info.totalram * info.mem_unit;
    unsigned long free_ram = info.freeram * info.mem_unit;
    unsigned long used_ram = total_ram - free_ram;

    return (float)used_ram * 100.0 / total_ram;
}

// Get disk usage percentage
float get_disk_usage(void) {
    struct statvfs stat;

    if (statvfs("/", &stat) != 0) {
        return -1.0;
    }

    unsigned long total_space = stat.f_blocks * stat.f_frsize;
    unsigned long free_space = stat.f_bfree * stat.f_frsize;
    unsigned long used_space = total_space - free_space;

    return (float)used_space * 100.0 / total_space;
}
