```c:client.c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <arpa/inet.h>

#define PORT 8080
#define BUFFER_SIZE 1024

// Function prototypes
void request_system_stat(int sock, const char* command);

int main(int argc, char const *argv[]) {
    int sock = 0;
    struct sockaddr_in serv_addr;
    int option;

    // Create socket
    if ((sock = socket(AF_INET, SOCK_STREAM, 0)) < 0) {
        printf("Socket creation error\n");
        return -1;
    }

    // Set up server address
    serv_addr.sin_family = AF_INET;
    serv_addr.sin_port = htons(PORT);

    // Convert IPv4 address from text to binary form
    if (inet_pton(AF_INET, "127.0.0.1", &serv_addr.sin_addr) <= 0) {
        printf("Invalid address or address not supported\n");
        return -1;
    }

    // Connect to server
    if (connect(sock, (struct sockaddr *)&serv_addr, sizeof(serv_addr)) < 0) {
        printf("Connection failed\n");
        return -1;
    }

    printf("Connected to server\n");

    // Menu for user
    while (1) {
        printf("\nSelect system statistic to fetch:\n");
        printf("1. CPU Usage\n");
        printf("2. Memory Usage\n");
        printf("3. Disk Usage\n");
        printf("4. Exit\n");
        printf("Enter option (1-4): ");

        if (scanf("%d", &option) != 1) {
            printf("Invalid input\n");
            while (getchar() != '\n'); // Clear input buffer
            continue;
        }

        switch (option) {
            case 1:
                request_system_stat(sock, "CPU_USAGE");
                break;
            case 2:
                request_system_stat(sock, "MEMORY_USAGE");
                break;
            case 3:
                request_system_stat(sock, "DISK_USAGE");
                break;
            case 4:
                close(sock);
                printf("Connection closed\n");
                return 0;
            default:
                printf("Invalid option\n");
                break;
        }
    }

    return 0;
}

// Public methods

// Send request to server for a specific system statistic
void request_system_stat(int sock, const char* command) {
    char buffer[BUFFER_SIZE] = {0};

    // Send the command to the server
    send(sock, command, strlen(command), 0);
    printf("Sent request: %s\n", command);

    // Receive response from server
    int bytes_read = read(sock, buffer, BUFFER_SIZE);
    if (bytes_read <= 0) {
        printf("Error reading from server\n");
        return;
    }

    buffer[bytes_read] = '\0';
    printf("Server response: %s\n", buffer);
}
