use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::time::{Duration, SystemTime};

/// A simple session manager for handling user authentication sessions
pub struct SessionManager {
    /// Maps user IDs to their session start times
    sessions: Arc<Mutex<HashMap<String, SystemTime>>>,
}

impl SessionManager {
    /// Creates a new SessionManager instance
    pub fn new() -> Self {
        SessionManager {
            sessions: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    /// Starts a new session for the given user ID
    pub fn start_session(&self, user_id: String) {
        let mut sessions = self.sessions.lock().unwrap();
        sessions.insert(user_id, SystemTime::now());
    }

    /// Checks if the session for the given user ID is still valid
    /// 
    /// Returns true if the session exists and is within the specified duration,
    /// false otherwise
    pub fn check_session(&self, user_id: String, session_duration: u32) -> bool {
        let sessions = self.sessions.lock().unwrap();

        if let Some(start_time) = sessions.get(&user_id) {
            match start_time.elapsed() {
                Ok(elapsed) => {
                    let duration_minutes = session_duration as u64 * 60;
                    elapsed <= Duration::from_secs(duration_minutes)
                },
                Err(_) => false, // Handle potential time errors gracefully
            }
        } else {
            false // No session exists for this user
        }
    }

    /// Ends the session for the given user ID
    pub fn end_session(&self, user_id: String) {
