```cpp
#include <iostream>
#include <vector>
#include <string>
#include <mutex>
#include <algorithm>

class MusicPlaylist {
private:
    std::vector<std::string> songs;
    size_t currentSongIndex;
    std::mutex playlistMutex;

public:
    MusicPlaylist() : currentSongIndex(0) {}

    void addSong(const std::string& songName) {
        std::lock_guard<std::mutex> lock(playlistMutex);
        songs.push_back(songName);
        std::cout << "Added song: " << songName << std::endl;
    }

    void removeSong(const std::string& songName) {
        std::lock_guard<std::mutex> lock(playlistMutex);
        auto it = std::find(songs.begin(), songs.end(), songName);

        if (it != songs.end()) {
            // Adjust current index if removing a song before it
            if (std::distance(songs.begin(), it) < static_cast<int>(currentSongIndex)) {
                currentSongIndex--;
            }
            // If removing the last song and it's the current one
            else if (currentSongIndex >= songs.size() - 1 && songs.size() > 0) {
                currentSongIndex = 0;
            }

            songs.erase(it);
            std::cout << "Removed song: " << songName << std::endl;
        } else {
            std::cout << "Error: Song '" << songName << "' not found in playlist" << std::endl;
        }
    }

    void play() {
        std::lock_guard<std::mutex> lock(playlistMutex);

        if (songs.empty()) {
            std::cout << "Playlist is empty. Add songs first." << std::endl;
            return;
        }

        std::cout << "Playing: " << songs[currentSongIndex] << std::endl;

        // Move to next song
        currentSongIndex = (currentSongIndex + 1) % songs.size();
    }

    void listSongs() {
        std::lock_guard<std::mutex> lock(playlistMutex);

        if (songs.empty()) {
            std::cout << "Playlist is empty." << std::endl;
            return;
        }

        std::cout << "Playlist contains:" << std::endl;
        for (size_t i = 0; i < songs.size(); ++i) {
            std::string currentMarker = (i == currentSongIndex) ? " (current)" : "";
            std::cout << i + 1 << ". " << songs[i] << currentMarker << std::endl;
        }
    }
};

int main() {
    MusicPlaylist playlist;
    std::string command, songName;

    std::cout << "Music Playlist Editor" << std::endl;
    std::cout << "Available commands: ADD song_name, REMOVE song_name, PLAY, LIST, EXIT" << std::endl;

    while (true) {
        std::cout << "> ";
        std::cin >> command;

        if (command == "ADD") {
            std::cin >> std::ws;
            std::getline(std::cin, songName);
            playlist.addSong(songName);
        } else if (command == "REMOVE") {
            std::cin >> std::ws;
            std::getline(std::cin, songName);
            playlist.removeSong(songName);
        } else if (command == "PLAY") {
            playlist.play();
        } else if (command == "LIST") {
            playlist.listSongs();
        } else if (command == "EXIT") {
            break;
        } else {
            std::cout << "Unknown command. Available commands: ADD song_name, REMOVE song_name, PLAY, LIST, EXIT" << std::endl;
        }
    }

    return 0;
}
