// Constants for operation codes
#define OP_ADD "ADD"
#define OP_SUBTRACT "SUBTRACT"
#define OP_MULTIPLY "MULTIPLY"
#define OP_DIVIDE "DIVIDE"
#define OP_EXIT "EXIT"

// Error messages
#define ERROR_INVALID_OPERATION "Error: Invalid operation."
#define ERROR_DIVISION_BY_ZERO "Error: Division by zero is not allowed."
#define ERROR_INVALID_FORMAT "Error: Invalid input format. Please use 'OPERATION x y'."

void calculator() {
    char operation[20];
    int operand1, operand2;
    int scanResult;

    printf("Simple Calculator (type EXIT to quit)\n");
    printf("Available operations: ADD, SUBTRACT, MULTIPLY, DIVIDE\n");
    printf("Format: OPERATION x y\n");

    while (1) {
        printf("> ");
        scanResult = scanf("%s", operation);

        // Check for EOF or exit command
        if (scanResult == EOF || strcmp(operation, OP_EXIT) == 0) {
            printf("Calculator exiting...\n");
            break;
        }

        // Check which operation to perform
        if (strcmp(operation, OP_ADD) == 0 || 
            strcmp(operation, OP_SUBTRACT) == 0 || 
            strcmp(operation, OP_MULTIPLY) == 0 || 
            strcmp(operation, OP_DIVIDE) == 0) {

            // Read the two operands
            if (scanf("%d %d", &operand1, &operand2) != 2) {
                printf("%s\n", ERROR_INVALID_FORMAT);
                // Clear input buffer
                while (getchar() != '\n');
                continue;
            }

            // Perform the selected operation
            if (strcmp(operation, OP_ADD) == 0) {
                printf("Result: %d\n", operand1 + operand2);
            } 
            else if (strcmp(operation, OP_SUBTRACT) == 0) {
                printf("Result: %d\n", operand1 - operand2);
            } 
            else if (strcmp(operation, OP_MULTIPLY) == 0) {
                printf("Result: %d\n", operand1 * operand2);
            } 
            else if (strcmp(operation, OP_DIVIDE) == 0) {
                if (operand2 == 0) {
                    printf("%s\n", ERROR_DIVISION_BY_ZERO);
                } else {
                    printf("Result: %d\n", operand1 / operand2);
                }
            }
        } 
        else {
            printf("%s\n", ERROR_INVALID_OPERATION);
        }

        // Clear input buffer
        while (getchar() != '\n');
    }
}

int main() {
    calculator();
    return 0;
}
