```rust:src/main.rs
use std::collections::HashMap;
use std::io::{BufRead, BufReader, Write};
use std::net::{TcpListener, TcpStream};
use std::sync::{Arc, Mutex};
use std::thread;

type ClientsMap = HashMap<String, TcpStream>;

struct ChatServer {
    clients: Arc<Mutex<ClientsMap>>,
}

impl ChatServer {
    fn new() -> ChatServer {
        ChatServer {
            clients: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    fn broadcast(&self, message: &str) -> Result<(), std::io::Error> {
        let mut clients = self.clients.lock().unwrap();
        let mut failed_clients: Vec<String> = Vec::new();

        for (username, stream) in clients.iter_mut() {
            if let Err(_) = stream.write_all(message.as_bytes()) {
                failed_clients.push(username.clone());
            }
        }

        for username in failed_clients {
            clients.remove(&username);
        }

        Ok(())
    }

    fn handle_client(&self, mut stream: TcpStream) {
        let stream_clone = stream.try_clone().unwrap();
        let reader = BufReader::new(stream_clone);
        let mut username: Option<String> = None;

        for line in reader.lines() {
            match line {
                Ok(line) => {
                    let parts: Vec<&str> = line.splitn(2, ' ').collect();
                    let command = parts[0];

                    match command {
                        "JOIN" => {
                            if parts.len() < 2 {
                                let _ = stream.write_all(b"Error: JOIN requires a username\n");
                                continue;
                            }

                            let new_username = parts[1].to_string();
                            let mut clients = self.clients.lock().unwrap();

                            if clients.contains_key(&new_username) {
                                let _ = stream.write_all(b"Error: Username already taken\n");
                                continue;
                            }

                            if let Some(existing_username) = &username {
                                clients.remove(existing_username);
                                let _ = self.broadcast(&format!("{} has changed name to {}\n", existing_username, new_username));
                            } else {
                                let _ = stream.try_clone().map(|s| {
                                    clients.insert(new_username.clone(), s);
                                    self.broadcast(&format!("{} has joined the chat\n", new_username))
                                });
                            }

                            username = Some(new_username);
                        },
                        "LEAVE" => {
                            if let Some(current_username) = &username {
                                let mut clients = self.clients.lock().unwrap();
                                clients.remove(current_username);
                                let _ = self.broadcast(&format!("{} has left the chat\n", current_username));
                                username = None;
                                break;
                            } else {
                                let _ = stream.write_all(b"Error: You are not in the chat\n");
                            }
                        },
                        "MESSAGE" => {
                            if parts.len() < 2 {
                                let _ = stream.write_all(b"Error: MESSAGE requires text\n");
                                continue;
                            }

                            if let Some(current_username) = &username {
                                let message = parts[1];
                                let _ = self.broadcast(&format!("{}: {}\n", current_username, message));
                            } else {
                                let _ = stream.write_all(b"Error: You must JOIN before sending messages\n");
                            }
                        },
                        "LIST" => {
                            let clients = self.clients.lock().unwrap();
                            let users_list = clients.keys().cloned().collect::<Vec<String>>().join(", ");
                            let _ = stream.write_all(format!("Connected users: {}\n", users_list).as_bytes());
                        },
                        _ => {
                            let _ = stream.write_all(b"Error: Unknown command. Available commands: JOIN, LEAVE, MESSAGE, LIST\n");
                        }
                    }
                },
                Err(_) => break,
            }
        }

        // Clean up if client disconnects
        if let Some(current_username) = &username {
            let mut clients = self.clients.lock().unwrap();
            clients.remove(current_username);
            let _ = self.broadcast(&format!("{} has left the chat\n", current_username));
        }
    }

    fn start(&self, address: &str) -> Result<(), std::io::Error> {
        let listener = TcpListener::bind(address)?;
        println!("Server listening on {}", address);

        for stream in listener.incoming() {
            match stream {
                Ok(stream) => {
                    let server_clone = ChatServer {
                        clients: Arc::clone(&self.clients),
                    };

                    thread::spawn(move || {
                        server_clone.handle_client(stream);
                    });
                }
                Err(e) => {
                    eprintln!("Connection failed: {}", e);
                }
            }
        }

        Ok(())
    }
}

fn main() -> Result<(), std::io::Error> {
    let server: ChatServer = ChatServer::new();
    server.start("127.0.0.1:8080")
}
