// userPreferenceManager.js

/**
 * User Preference Manager Utility
 * Manages user preferences using functional programming principles
 */
const userPreferenceManager = (() => {
  // Internal state
  const state = {
    preferences: new Map()
  };

  /**
   * Adds or updates a user's preference
   * @param {string} user - User identifier
   * @param {Object} preference - Preference object to store
   * @returns {Object} Updated preferences object
   */
  const addPreference = (user, preference) => {
    const currentPreferences = state.preferences.get(user) || {};
    const updatedPreferences = { ...currentPreferences, ...preference };
    state.preferences.set(user, updatedPreferences);
    return { ...updatedPreferences };
  };

  /**
   * Retrieves the current preference of a user
   * @param {string} user - User identifier
   * @returns {Object|null} User's preferences or null if not found
   */
  const getPreference = (user) => {
    const userPreference = state.preferences.get(user);
    return userPreference ? { ...userPreference } : null;
  };

  /**
   * Deletes the preference setting of a specified user
   * @param {string} user - User identifier
   * @returns {boolean} True if successful, false if user not found
   */
  const removePreference = (user) => {
    return state.preferences.delete(user);
  };

  // Public API
  return {
    addPreference,
    getPreference,
    removePreference
  };
})();

export default userPreferenceManager;
