import java.util.Scanner;

public class NutritionTracker {
    private List<FoodItem> foodItems;

    public NutritionTracker() {
        this.foodItems = new ArrayList<>();
    }

    /**
     * Adds a food item to the tracker with its nutritional values
     * 
     * @param foodName The name of the food
     * @param calories The caloric content of the food
     * @param carbs The carbohydrate content in grams
     * @param protein The protein content in grams
     * @param fats The fat content in grams
     * @throws IllegalArgumentException if any nutritional value is negative
     */
    public void addFood(String foodName, double calories, double carbs, double protein, double fats) {
        // Input validation
        String errorMessage = "";
        boolean hasError = false;

        if (calories < 0) {
            errorMessage += "Calories cannot be negative. ";
            hasError = true;
        }

        if (carbs < 0) {
            errorMessage += "Carbohydrates cannot be negative. ";
            hasError = true;
        }

        if (protein < 0) {
            errorMessage += "Protein cannot be negative. ";
            hasError = true;
        }

        if (fats < 0) {
            errorMessage += "Fats cannot be negative. ";
            hasError = true;
        }

        if (hasError) {
            throw new IllegalArgumentException(errorMessage);
        }

        // Create and add the food item
        FoodItem newFood = new FoodItem(foodName, calories, carbs, protein, fats);
        this.foodItems.add(newFood);
        System.out.println(foodName + " added successfully!");
    }

    /**
     * Calculates the total nutritional values from all added food items
     * 
     * @return A NutritionInfo object containing the total nutritional values
     */
    public NutritionInfo totalNutrition() {
        double totalCalories = 0.0;
        double totalCarbs = 0.0;
        double totalProtein = 0.0;
        double totalFats = 0.0;

        for (FoodItem item : this.foodItems) {
            totalCalories += item.getCalories();
            totalCarbs += item.getCarbs();
            totalProtein += item.getProtein();
            totalFats += item.getFats();
        }

        NutritionInfo totals = new NutritionInfo(totalCalories, totalCarbs, totalProtein, totalFats);
        return totals;
    }

    /**
     * Display the total nutrition information in a formatted way
     */
    public void displayTotalNutrition() {
        NutritionInfo totals = this.totalNutrition();
        System.out.println("\n----- Nutrition Summary -----");
        System.out.printf("Total Calories: %.2f cal\n", totals.getCalories());
        System.out.printf("Total Carbohydrates: %.2f g\n", totals.getCarbs());
        System.out.printf("Total Protein: %.2f g\n", totals.getProtein());
        System.out.printf("Total Fats: %.2f g\n", totals.getFats());
        System.out.println("----------------------------");
    }

