```c
#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_ACCOUNTS 100

// Structure to represent a bank account
typedef struct {
    int customerId;
    double balance;
    bool isActive;
} Account;

// Global variables
Account accounts[MAX_ACCOUNTS];
int accountCount = 0;

// Function prototypes
bool createAccount(int customerId, double initialBalance);
bool deposit(int customerId, double amount);
bool withdraw(int customerId, double amount);
double getBalance(int customerId);
bool closeAccount(int customerId);
int findAccountIndex(int customerId);

int main() {
    // Sample usage of the banking system
    printf("Banking System Simulation\n");
    printf("-------------------------\n");

    // Create some sample accounts
    createAccount(1001, 500.00);
    createAccount(1002, 1000.00);

    // Perform operations
    printf("Balance for customer 1001: $%.2f\n", getBalance(1001));
    deposit(1001, 250.00);
    printf("Balance after deposit: $%.2f\n", getBalance(1001));
    withdraw(1001, 100.00);
    printf("Balance after withdrawal: $%.2f\n", getBalance(1001));

    // Test error cases
    withdraw(1001, 1000.00); // Insufficient balance
    getBalance(1003);        // Non-existent customer

    // Close an account
    closeAccount(1001);
    getBalance(1001);        // Closed account

    return 0;
}

// Function to find the index of an account by customerId
int findAccountIndex(int customerId) {
    int i;
    for (i = 0; i < accountCount; i++) {
        if (accounts[i].customerId == customerId && accounts[i].isActive) {
            return i;
        }
    }
    return -1; // Not found or inactive
}

// Function to create a new account
bool createAccount(int customerId, double initialBalance) {
    // Check if the account already exists
    if (findAccountIndex(customerId) != -1) {
        printf("Error: Customer ID %d already exists.\n", customerId);
        return false;
    }

    // Check if we've reached the maximum number of accounts
    if (accountCount >= MAX_ACCOUNTS) {
        printf("Error: Cannot create more accounts. Maximum limit reached.\n");
        return false;
    }

    // Check if initial balance is valid
    if (initialBalance < 0) {
        printf("Error: Initial balance cannot be negative.\n");
        return false;
    }

    // Create the account
    accounts[accountCount].customerId = customerId;
    accounts[accountCount].balance = initialBalance;
    accounts[accountCount].isActive = true;
    accountCount++;

    printf("Account created successfully for customer ID %d with initial balance $%.2f\n", 
           customerId, initialBalance);
    return true;
}

// Function to deposit money into an account
bool deposit(int customerId, double amount) {
    int accountIndex = findAccountIndex(customerId);

    // Check if the account exists
    if (accountIndex == -1) {
        printf("Error: Customer ID %d not found or account is closed.\n", customerId);
        return false;
    }

    // Check if amount is valid
    if (amount <= 0) {
        printf("Error: Deposit amount must be positive.\n");
        return false;
    }

    // Update balance
    accounts[accountIndex].balance += amount;
    printf("Successfully deposited $%.2f to account %d. New balance: $%.2f\n", 
           amount, customerId, accounts[accountIndex].balance);
    return true;
}

// Function to withdraw money from an account
bool withdraw(int customerId, double amount) {
    int accountIndex = findAccountIndex(customerId);

    // Check if the account exists
    if (accountIndex == -1) {
        printf("Error: Customer ID %d not found or account is closed.\n", customerId);
        return false;
    }

    // Check if amount is valid
    if (amount <= 0) {
        printf("Error: Withdrawal amount must be positive.\n");
        return false;
    }

    // Check if sufficient balance
    if (accounts[accountIndex].balance < amount) {
        printf("Error: Insufficient balance for customer ID %d. Current balance: $%.2f\n", 
               customerId, accounts[accountIndex].balance);
        return false;
    }

    // Update balance
    accounts[accountIndex].balance -= amount;
