def register_voter(voter_id: str, voters: set = None) -> str:
    if voters is None:
        voters = set()

    if voter_id in voters:
        return f"Voter {voter_id} is already registered"

    voters.add(voter_id)
    return f"Voter {voter_id} registered successfully"

def unregister_voter(voter_id: str, voters: set = None) -> str:
    if voters is None:
        voters = set()

    if voter_id not in voters:
        return f"Error: Voter {voter_id} is not registered"

    voters.remove(voter_id)
    return f"Voter {voter_id} unregistered successfully"

def vote(voter_id: str, candidate: str, voters: set = None, votes: dict = None) -> str:
    if voters is None:
        voters = set()
    if votes is None:
        votes = {}

    if voter_id not in voters:
        return f"Error: Voter {voter_id} is not registered"

    votes[candidate] = votes.get(candidate, 0) + 1
    return f"Vote for {candidate} recorded successfully"

