use std::collections::HashMap;
use std::io::{self, Write};

// Constants
const MAX_STUDENTS: usize = 100;

struct AttendanceSystem {
    students: HashMap<String, bool>,
}

impl AttendanceSystem {
    fn new() -> Self {
        Self {
            students: HashMap::new(),
        }
    }

    fn add_student(&mut self, name: &str) -> Result<(), String> {
        if self.students.len() >= MAX_STUDENTS {
            return Err(format!("Cannot add student: Maximum limit of {} students reached", MAX_STUDENTS));
        }

        if self.students.contains_key(name) {
            return Err(format!("Student '{}' already exists", name));
        }

        self.students.insert(name.to_string(), false);
        Ok(())
    }

    fn remove_student(&mut self, name: &str) -> Result<(), String> {
        if !self.students.contains_key(name) {
            return Err(format!("Cannot remove: Student '{}' does not exist", name));
        }

        self.students.remove(name);
        Ok(())
    }

    fn check_in(&mut self, name: &str) -> Result<(), String> {
        if !self.students.contains_key(name) {
            return Err(format!("Cannot check in: Student '{}' does not exist", name));
        }

        *self.students.get_mut(name).unwrap() = true;
        Ok(())
    }

    fn report(&self) {
        println!("\nAttendance Report:");
        println!("-----------------");

        if self.students.is_empty() {
            println!("No students registered.");
            return;
        }

        let mut students: Vec<_> = self.students.iter().collect();
        students.sort_by(|a, b| a.0.cmp(b.0));

        for (name, present) in students {
            let status = if *present { "Present" } else { "Absent" };
            println!("{}: {}", name, status);
        }
    }
}

fn main() {
    let mut system = AttendanceSystem::new();

    println!("Student Attendance System");
    println!("Commands: ADD <name>, REMOVE <name>, CHECK_IN <name>, REPORT, EXIT");

    loop {
        print!("> ");
        io::stdout().flush().unwrap();

        let mut input = String::new();
        io::stdin().read_line(&mut input).unwrap();
        let input = input.trim();

        let parts: Vec<&str> = input.splitn(2, ' ').collect();
        let command = parts[0].to_uppercase();

        match command.as_str() {
            "ADD" => {
                if parts.len() < 2 || parts[1].is_empty() {
                    println!("Error: ADD command requires a student name");
                    continue;
                }

                match system.add_student(parts[1]) {
                    Ok(()) => println!("Student '{}' added successfully", parts[1]),
                    Err(e) => println!("Error: {}", e),
                }
            },
            "REMOVE" => {
                if parts.len() < 2 || parts[1].is_empty() {
                    println!("Error: REMOVE command requires a student name");
                    continue;
                }

                match system.remove_student(parts[1]) {
                    Ok(()) => println!("Student '{}' removed successfully", parts[1]),
                    Err(e) => println!("Error: {}", e),
                }
            },
            "CHECK_IN" => {
                if parts.len() < 2 || parts[1].is_empty() {
                    println!("Error: CHECK_IN command requires a student name");
                    continue;
                }

                match system.check_in(parts[1]) {
                    Ok(()) => println!("Student '{}' checked in successfully", parts[1]),
                    Err(e) => println!("Error: {}", e),
                }
            },
            "REPORT" => {
                system.report();
            },
            "EXIT" => {
                println!("Exiting attendance system. Goodbye!");
                break;
            },
            _ => {
                println!("Unknown command. Available commands: ADD, REMOVE, CHECK_IN, REPORT, EXIT");
            },
        }
    }
}
