Here's a C program that implements a basic process management scheduler with the specified operations:

```c
#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

#define MAX_TASKS 100
#define MAX_COMMAND_LENGTH 50

typedef struct {
    int task_id;
    int priority;
} Task;

typedef struct {
    Task tasks[MAX_TASKS];
    int count;
} Scheduler;

// Initialize the scheduler
void initialize_scheduler(Scheduler* scheduler) {
    scheduler->count = 0;
}

// Find a task by ID, returns index or -1 if not found
int find_task_index(Scheduler* scheduler, int task_id) {
    for (int i = 0; i < scheduler->count; i++) {
        if (scheduler->tasks[i].task_id == task_id) {
            return i;
        }
    }
    return -1;
}

// Add a new task to the scheduler
bool add_task(Scheduler* scheduler, int task_id, int priority) {
    // Check if scheduler is full
    if (scheduler->count >= MAX_TASKS) {
        printf("Error: Scheduler is full\n");
        return false;
    }

    // Check if task_id already exists
    if (find_task_index(scheduler, task_id) != -1) {
        printf("Error: Task ID %d already exists\n", task_id);
        return false;
    }

    // Add new task
    scheduler->tasks[scheduler->count].task_id = task_id;
    scheduler->tasks[scheduler->count].priority = priority;
    scheduler->count++;
    printf("Added task %d with priority %d\n", task_id, priority);
    return true;
}

// Remove a task from the scheduler
bool remove_task(Scheduler* scheduler, int task_id) {
    int index = find_task_index(scheduler, task_id);

    if (index == -1) {
        printf("Error: Task ID %d not found\n", task_id);
        return false;
    }

    // Shift all tasks after the removed one
    for (int i = index; i < scheduler->count - 1; i++) {
        scheduler->tasks[i] = scheduler->tasks[i + 1];
    }

    scheduler->count--;
    printf("Removed task %d\n", task_id);
    return true;
}

// Change the priority of an existing task
bool change_priority(Scheduler* scheduler, int task_id, int new_priority) {
    int index = find_task_index(scheduler, task_id);

    if (index == -1) {
        printf("Error: Task ID %d not found\n", task_id);
        return false;
    }

    scheduler->tasks[index].priority = new_priority;
    printf("Changed priority of task %d to %d\n", task_id, new_priority);
    return true;
}

// Fetch and remove the highest priority task
bool fetch_next_task(Scheduler* scheduler, Task* result) {
    if (scheduler->count == 0) {
        printf("Error: No tasks in scheduler\n");
        return false;
    }

    // Find highest priority task
    int highest_priority_index = 0;
    for (int i = 1; i < scheduler->count; i++) {
        if (scheduler->tasks[i].priority > scheduler->tasks[highest_priority_index].priority) {
            highest_priority_index = i;
        }
    }

    // Copy task to result
    *result = scheduler->tasks[highest_priority_index];

    // Remove the task
    for (int i = highest_priority_index; i < scheduler->count - 1; i++) {
        scheduler->tasks[i] = scheduler->tasks[i + 1];
    }

    scheduler->count--;
    return true;
}

int main() {
    Scheduler scheduler;
    initialize_scheduler(&scheduler);

    char command[MAX_COMMAND_LENGTH];
    int task_id, priority;

    printf("Process Scheduler\n");
    printf("Available commands:\n");
    printf("- ADD_TASK <task_id> <priority>\n");
    printf("- REMOVE_TASK <task_id>\n");
    printf("- CHANGE_PRIORITY <task_id> <new_priority>\n");
    printf("- FETCH_NEXT_TASK\n");
    printf("- EXIT\n\n");

    while (1) {
        printf("> ");
        scanf("%s", command);

        if (strcmp(command, "ADD_TASK") == 0) {
            scanf("%d %d", &task_id, &priority);
            add_task(&scheduler, task_id, priority);
        } 
        else if (strcmp(command, "REMOVE_TASK") == 0) {
            scanf("%d", &task_id);
            remove_task(&scheduler, task_id);
        } 
        else if (strcmp(command, "CHANGE_PRIORITY") == 0) {
            scanf("%d %d", &task_id, &priority);
            change_priority(&scheduler, task_id, priority);
        } 
        else if (strcmp(command, "FETCH_NEXT_TASK") == 0) {
            Task next_task;
            if (fetch_next_task(&scheduler, &next_task)) {
                printf("Fetched task %d with priority %d\n", 
                       next_task.task_id, next_task.priority);
            }
        } 
        else if (strcmp(command, "EXIT") == 0) {
            break;
        } 
        else {
            printf("Error: Unknown command\n");
        }
    }

    return 0;
}
