function calculateTimeSpan(startTimeStamp, endTimeStamp) {
  // Validate inputs
  const startDate = new Date(startTimeStamp);
  const endDate = new Date(endTimeStamp);

  if (isNaN(startDate.getTime())) {
    throw new Error("Invalid start timestamp provided");
  }

  if (isNaN(endDate.getTime())) {
    throw new Error("Invalid end timestamp provided");
  }

  if (endDate < startDate) {
    throw new Error("End timestamp cannot be earlier than start timestamp");
  }

  // Constants for time calculations
  const secondsPerMinute = 60;
  const minutesPerHour = 60;
  const hoursPerDay = 24;
  const millisecondsPerSecond = 1000;

  // Calculate total difference in milliseconds
  const diffMs = endDate.getTime() - startDate.getTime();

  // Calculate individual time components
  let remainingMs = diffMs;

  // Calculate years
  const msPerYear = millisecondsPerSecond * secondsPerMinute * minutesPerHour * hoursPerDay * 365;
  const years = Math.floor(remainingMs / msPerYear);
  remainingMs = remainingMs % msPerYear;

  // Calculate months (approximation)
  const msPerMonth = msPerYear / 12;
  const months = Math.floor(remainingMs / msPerMonth);
  remainingMs = remainingMs % msPerMonth;

  // Calculate days
  const msPerDay = millisecondsPerSecond * secondsPerMinute * minutesPerHour * hoursPerDay;
  const days = Math.floor(remainingMs / msPerDay);
  remainingMs = remainingMs % msPerDay;

  // Calculate hours
  const msPerHour = millisecondsPerSecond * secondsPerMinute * minutesPerHour;
  const hours = Math.floor(remainingMs / msPerHour);
  remainingMs = remainingMs % msPerHour;

  // Calculate minutes
  const msPerMinute = millisecondsPerSecond * secondsPerMinute;
  const minutes = Math.floor(remainingMs / msPerMinute);
  remainingMs = remainingMs % msPerMinute;

  // Calculate seconds
  const seconds = Math.floor(remainingMs / millisecondsPerSecond);

  return { years, months, days, hours, minutes, seconds };
}
