    Flight(const std::string& id, const std::string& destination, int capacity) 
        : flightID(id), flightDestination(destination), maxCapacity(capacity) {}

    bool bookPassenger(const std::string& passengerName) {
        if (static_cast<int>(passengers.size()) >= maxCapacity) {
            std::cout << "Error: Flight " << flightID << " is fully booked." << std::endl;
            return false;
