            return false;
        }

        passengers.push_back(passengerName);
        std::cout << "Booked " << passengerName << " on flight " << flightID << " successfully." << std::endl;
        return true;
    }

    bool cancelBooking(const std::string& passengerName) {
        auto it = std::find(passengers.begin(), passengers.end(), passengerName);
        if (it == passengers.end()) {
            std::cout << "Error: " << passengerName << " is not booked on flight " << flightID << "." << std::endl;
            return false;
        }

        passengers.erase(it);
        std::cout << "Cancelled booking for " << passengerName << " on flight " << flightID << " successfully." << std::endl;
