import java.util.HashMap;
import java.util.Map;

public class ParkingGarage {
    private int totalSpaces;
    private int availableSpaces;
    private Map<String, ParkingRecord> parkedVehicles;

    public ParkingGarage(int totalSpaces) {
        this.totalSpaces = totalSpaces;
        this.availableSpaces = totalSpaces;
        this.parkedVehicles = new HashMap<>();
    }

    public String parkVehicle(String licensePlate) {
        if (licensePlate == null || licensePlate.trim().isEmpty()) {
            throw new IllegalArgumentException("License plate cannot be null or empty");
        }

        if (parkedVehicles.containsKey(licensePlate)) {
            return "Vehicle with license plate " + licensePlate + " is already parked";
        }

        if (availableSpaces <= 0) {
            return "Parking garage is full. No available spaces.";
        }

        ParkingRecord parkingRecord = new ParkingRecord(licensePlate, System.currentTimeMillis());
        parkedVehicles.put(licensePlate, parkingRecord);
        availableSpaces--;

        return "Vehicle with license plate " + licensePlate + " successfully parked";
    }

    public String departVehicle(String licensePlate) {
        if (licensePlate == null || licensePlate.trim().isEmpty()) {
            throw new IllegalArgumentException("License plate cannot be null or empty");
        }

        if (!parkedVehicles.containsKey(licensePlate)) {
            return "Vehicle with license plate " + licensePlate + " is not parked in this garage";
        }

        parkedVehicles.remove(licensePlate);
        availableSpaces++;

        return "Vehicle with license plate " + licensePlate + " successfully departed";
    }

    public int countAvailableSpaces() {
        return availableSpaces;
    }

    private static class ParkingRecord {
        private String licensePlate;
        private long entryTime;

        public ParkingRecord(String licensePlate, long entryTime) {
            this.licensePlate = licensePlate;
            this.entryTime = entryTime;
        }
    }

    public static void main(String[] args) {
        // Example usage
        ParkingGarage garage = new ParkingGarage(100);

        System.out.println(garage.parkVehicle("ABC123"));
        System.out.println("Available spaces: " + garage.countAvailableSpaces());

        System.out.println(garage.parkVehicle("XYZ789"));
        System.out.println("Available spaces: " + garage.countAvailableSpaces());

        System.out.println(garage.departVehicle("ABC123"));
        System.out.println("Available spaces: " + garage.countAvailableSpaces());

        System.out.println(garage.departVehicle("DEF456")); // Attempting to depart a vehicle that isn't parked
    }
}
