package com.profiles.service;

import com.profiles.model.UserProfile;
import org.springframework.stereotype.Service;

import java.util.HashMap;
import java.util.Map;
import java.util.Optional;

@Service
public class UserProfileService {
    private final Map<String, UserProfile> profiles = new HashMap<>();

    public UserProfile createProfile(UserProfile profile) {
        profiles.put(profile.getUsername(), profile);
        return profile;
    }

    public Optional<UserProfile> getProfile(String username) {
        return Optional.ofNullable(profiles.get(username));
    }

    public Optional<UserProfile> updateProfile(String username, UserProfile updatedProfile) {
        if (profiles.containsKey(username)) {
            UserProfile existingProfile = profiles.get(username);

            if (updatedProfile.getEmail() != null) {
                existingProfile.setEmail(updatedProfile.getEmail());
            }

            if (updatedProfile.getAge() > 0) {
                existingProfile.setAge(updatedProfile.getAge());
            }

            return Optional.of(existingProfile);
        }
        return Optional.empty();
    }

    public boolean deleteProfile(String username) {
        return profiles.remove(username) != null;
    }
