package com.profiles.controller;

import com.profiles.model.UserProfile;
import com.profiles.service.UserProfileService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
public class UserProfileController {

    private final UserProfileService userProfileService;

    @Autowired
    public UserProfileController(UserProfileService userProfileService) {
        this.userProfileService = userProfileService;
    }

    @PostMapping("/profiles")
    public ResponseEntity<UserProfile> createProfile(@RequestBody UserProfile profile) {
        UserProfile createdProfile = userProfileService.createProfile(profile);
        return new ResponseEntity<>(createdProfile, HttpStatus.CREATED);
    }

    @GetMapping("/profile/{username}")
    public ResponseEntity<UserProfile> getProfile(@PathVariable String username) {
        return userProfileService.getProfile(username)
                .map(profile -> new ResponseEntity<>(profile, HttpStatus.OK))
                .orElse(new ResponseEntity<>(HttpStatus.NOT_FOUND));
    }

    @PutMapping("/profile/{username}")
    public ResponseEntity<UserProfile> updateProfile(
            @PathVariable String username,
            @RequestBody UserProfile profile) {
        return userProfileService.updateProfile(username, profile)
                .map(updatedProfile -> new ResponseEntity<>(updatedProfile, HttpStatus.OK))
                .orElse(new ResponseEntity<>(HttpStatus.NOT_FOUND));
    }

    @DeleteMapping("/profile/{username}")
    public ResponseEntity<Void> deleteProfile(@PathVariable String username) {
        if (userProfileService.deleteProfile(username)) {
            return new ResponseEntity<>(HttpStatus.NO_CONTENT);
        } else {
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        }
    }
}
