#include <iostream>
#include <stdexcept>

template <typename T>
class LinkedStack {
private:
    // Node structure for the linked list
    struct Node {
        T data;
        Node* next;

        // Constructor for Node
        Node(const T& value) : data(value), next(nullptr) {}
    };

    // Private member variables
    Node* topNode;
    int stackSize;

public:
    // Constructor
    LinkedStack() : topNode(nullptr), stackSize(0) {}

    // Destructor
    ~LinkedStack() {
        // Clean up all nodes
        while (!isEmpty()) {
            pop();
        }
    }

    // Push operation - adds element to the top of the stack
    void push(const T& value) {
        // Create a new node
        Node* newNode = new Node(value);

        // Set the next pointer of the new node to the current top
        newNode->next = topNode;

        // Update the top pointer to the new node
        topNode = newNode;

        // Increment the size counter
        stackSize++;
    }

    // Pop operation - removes and returns the top element
    T pop() {
        // Check if stack is empty
        if (isEmpty()) {
            throw std::underflow_error("Stack underflow: Cannot pop from an empty stack");
        }

        // Store the current top node
        Node* temp = topNode;

        // Store the data from the top node
        T value = temp->data;

        // Update the top pointer to the next node
        topNode = topNode->next;

        // Delete the old top node
        delete temp;

        // Decrement the size counter
        stackSize--;

        // Return the value
        return value;
    }

    // Peek operation - returns the top element without removing it
    T peek() const {
        // Check if stack is empty
        if (isEmpty()) {
            throw std::underflow_error("Stack underflow: Cannot peek an empty stack");
        }

        // Return the data from the top node
        return topNode->data;
    }

    // Size operation - returns the number of elements in the stack
    int size() const {
        return stackSize;
    }

    // isEmpty operation - checks if the stack is empty
    bool isEmpty() const {
        return topNode == nullptr;
    }
};
