function createRateLimiter(maxCallsPerMinute, resetIntervalMs = 60000) {
  let tokens = maxCallsPerMinute;
  let lastRefillTimestamp = Date.now();

  return function checkRateLimit() {
    const currentTime = Date.now();
    const timeElapsedSinceLastRefill = currentTime - lastRefillTimestamp;

    if (timeElapsedSinceLastRefill >= resetIntervalMs) {
      tokens = maxCallsPerMinute;
      lastRefillTimestamp = currentTime;
    }

    if (tokens > 0) {
      tokens -= 1;
      return true;
    }

    return false;
  };
